    {
      "n": 109,
      "column": "left",
      "text": "Manna Dwehfele stahw\nweenumebr manna Rohka/ tat-\nschu es tawu Baustibu ne ais-\nmirstu.\n"
    },
    {
      "n": 110,
      "column": "left",
      "text": "Tee Besdeewigee leek\nman Walgus/tatfchu es ne allo-\njohs no tawahm Pawehlefcha-\nnahm.\n"
    },
    {
      "n": 111,
      "column": "left",
      "text": "Tawas Leezibas turru\nes par mannu Mantu muhshi-\ngi/ jo tahs irr mannas Sirds\nLihgfimiba.\n"
    },
    {
      "n": 112,
      "column": "left",
      "text": "Es atgreeschu fawn\nSirdi tawus Likkumus padar-\nriht muhscham lihds patt Gal-\nlam.\n"
    },
    {
      "n": 113,
      "column": "left",
      "text": "Es eenihstu tohs Dasch-\nprahtigus/ un mihleju tawu\nBaustibu.\n"
    },
    {
      "n": 114,
      "column": "left",
      "text": "Tu efi mans Patwe-\nrums/ un mannas preefschtur-\nramas Bruņnas / us tawu\nWahrdu gaidu es.\n"
    },
    {
      "n": 115,
      "column": "left",
      "text": "Atstahjeet no mannim\njuhs Launadarritaji/ ka es man-\nna Deewa Baustus turreht\nwarri.\n"
    },
    {
      "n": 116,
      "column": "left",
      "text": "Usturri mann pehz ta-\nta Wahrdn/ ka es dshwoju/ un\nlai es Kannā ne tohpu pahr\nmannu Zerribu.\n"
    },
    {
      "n": 117,
      "column": "right",
      "text": "Stiprini mann/ ka es at-\nweHelejohs/ tad es eeksch taweein\nLikkumeem eelihgfmofchohs wee-\numehr.\n"
    },
    {
      "n": 118,
      "column": "right",
      "text": "Tu faminni wiffus/ kas\nno taweein Likkumeem nomalda/\njo wiknu Wiltiba irr tibri Melli.\n"
    },
    {
      "n": 119,
      "column": "right",
      "text": "Tu atmett wiffus Bes-\ndeewigus tvrs Seumes / ka\nSahrans/ tadeht mihleju es ta-\nwas Leezibas.\n"
    },
    {
      "n": 120,
      "column": "right",
      "text": "Es ta bihstobs preeksch\ntewis / ka Schauschalas pahr\nmannahn Meeiahm eet / un\nman irr bait preeksch tawahm\nSohdibahm.\n"
    },
    {
      "n": 121,
      "column": "right",
      "text": "Es darri Teesu un\nTaifnibu/ ne nodehd mann\nmanneem Warras Darrita-\njeem.\n"
    },
    {
      "n": 122,
      "column": "right",
      "text": "Galwo tu preeksch ta-\nwu Kalpu us Labbu/ ka tee Lep-\nnee mann ne pahrwarr.\n"
    },
    {
      "n": 123,
      "column": "right",
      "text": "Mannas Azzis ilgojahs\npehz tawas Pestitchanas / un\npehz tawas Taifnibus Apsohli-\nchanas.\n"
    },
    {
      "n": 124,
      "column": "right",
      "text": "Darri pee tawa Kalpa\npehz tawas Schehlastibas/ un\nmahzi man tawus Likkumus.\n"
    },
    {
      "n": 125,
      "column": "right",
      "text": "Es efinu taws Kalps/\npadarri mann gudru / ka es ta-\nwas Leezibas atsibstu.\n"
    },
    {
      "n": 126,
      "column": "right",
      "text": "Jo Laiks irr/ ka tas\nKUÑGS fahk darbotees/tee irr\ntawu Baustibu faraustijschi.\n"
    },
    {
      "n": 127,
      "column": "right",
      "text": "Tadeht mihleju es ta-\nwas Baustibas wairak/ ne ka\nSelru/ un schkibstu Selru.\n"
    },
    {
      "n": 128,
      "column": "right",
      "text": "Tadeht turru es wiffas\nEeeeee Paweb-\n"
